return items.map(item => {
  const key = item.json?.body?.data?.key ?? {};
  const texto = item.json?.Resposta || "Recebido!";

  const remoteJid    = (key.remoteJid    || "").trim();
  const remoteJidAlt = (key.remoteJidAlt || "").trim();

  const isRealJid = (jid) => /@(s\.whatsapp\.net|c\.us)$/i.test(jid);
  const toNumber  = (jid) =>
    (jid || "")
      .replace(/@s\.whatsapp\.net$/i, "")
      .replace(/@c\.us$/i, "")
      .replace(/\D/g, "");

  let chosenJid = "";
  let number    = "";
  let halt      = false;

  if (remoteJid && isRealJid(remoteJid)) {
    chosenJid = remoteJid;
  } else if (remoteJidAlt && isRealJid(remoteJidAlt)) {
    chosenJid = remoteJidAlt;
  } else {
    // nem remoteJid nem remoteJidAlt trouxeram JID "real" => para o fluxo
    halt = true;
  }

  if (!halt) {
    number = toNumber(chosenJid);
    if (!number) {
      // algo muito fora do padrão: para com segurança
      halt = true;
    }
  }

  return {
    json: {
      remoteJid,
      remoteJidAlt,
      chosenJid,   // para debug
      number,      // E.164 sem sufixo
      halt,        // se true, seu IF interrompe
      replyText: texto
    }
  };
});

